# # utils/icons.py
# #
# # INLINE SVG ICON LIBRARY — TWO-TIER, EXTENSIBLE
# # ═══════════════════════════════════════════════
# # Every icon is pure inline SVG — NO CDN, NO font dependency.
# # Renders perfectly in Playwright PDF because it is just <svg> markup.
# #
# # TIER 1 — GENERIC ICONS: Universal UI stroked icons (server, alert, chart…)
# # TIER 2 — BRAND ICONS:   Real tech brand logos (kubernetes, docker, aws…)
# #           These use the ACTUAL brand SVG fill-paths, not approximations.
# #
# # EXTENSIBILITY — Three ways to add new icons:
# #   1. Edit ICON_PATHS / BRAND_ICONS in this file (permanent)
# #   2. Call register() at runtime (per-run, no file edit needed)
# #   3. Call register_topic() to add a new topic→icon mapping
# #
# # TOPIC AUTO-DETECTION:
# #   suggest_icons_for_topic("kubernetes docker") returns the best icon
# #   names to inject into prompts, so the LLM uses kubernetes/docker
# #   icons when generating a Kubernetes PDF — not generic server icons.
# #
# # USAGE:
# #   from utils.icons import icon, suggest_icons_for_topic, register
# #   icon("kubernetes", 64, "#326CE5")  → real Kubernetes wheel SVG
# #   icon("docker",     48, "#2496ED")  → real Docker whale SVG
# #   icon("server",     32, "#666")     → generic server stroked SVG

# from __future__ import annotations
# import re
# from typing import Optional


