# ══════════════════════════════════════════════════════════════════
#  TIER 3 — LETTER BADGE FALLBACK
#  When brand name is unknown, generate a clean professional badge.
#  Deterministic color from name hash ensures same brand → same color.
# ══════════════════════════════════════════════════════════════════

# Brand-specific colors for the letter badge (when we know the brand but not the SVG)
BRAND_COLORS: dict[str, str] = {
    "flutter": "#54C5F8", "dart": "#00B4AB", "react": "#61DAFB",
    "vue": "#42B883", "angular": "#DD0031", "svelte": "#FF3E00",
    "typescript": "#3178C6", "javascript": "#F7DF1E", "webpack": "#8DD6F9",
    "vite": "#646CFF", "nextjs": "#000000", "nuxt": "#00DC82",
    "deno": "#000000", "bun": "#FBF0DF",
    "spring": "#6DB33F", "django": "#092E20", "flask": "#000000",
    "rails": "#CC0000", "laravel": "#FF2D20", "symfony": "#000000",
    "dotnet": "#512BD4", "csharp": "#239120", "php": "#777BB4",
    "swift": "#F05138", "kotlin": "#7F52FF", "scala": "#DC322F",
    "r": "#276DC3", "julia": "#9558B2",
    "neo4j": "#008CC1", "influxdb": "#22ADF6", "clickhouse": "#FFCC01",
    "snowflake": "#29B5E8", "bigquery": "#4285F4", "redshift": "#8C4FFF",
    "databricks": "#FF3621", "dbt": "#FF694B",
    "ansible": "#EE0000", "puppet": "#FFAE1A", "chef": "#F09820",
    "vagrant": "#1563FF", "packer": "#02A8EF",
    "argocd": "#EF7B4D", "fluxcd": "#5468FF", "spinnaker": "#139BB4",
    "harbor": "#60B932", "containerd": "#575757",
    "cilium": "#F8C517", "calico": "#FB8C00", "flannel": "#0078D4",
    "envoy": "#AC6199",
    "vault": "#000000", "boundary": "#F24C53", "waypoint": "#14C6CB",
    "nomad": "#00CA8E",
}


def _letter_badge(name: str, size: int, color: str) -> str:
    """
    Generate a clean letter badge SVG for unknown brand icons.
    Uses the first letter of the name on a colored background.
    Color is deterministic from name hash if not in BRAND_COLORS.
    """
    # Resolve color: explicit > brand-specific > hash-based
    if color and color != "currentColor" and color.startswith("#"):
        bg_color = color
    elif name.lower() in BRAND_COLORS:
        bg_color = BRAND_COLORS[name.lower()]
    else:
        # Deterministic color from name hash — consistent across runs
        h = int(hashlib.md5(name.encode()).hexdigest()[:6], 16)
        hue = h % 360
        # Generate a vibrant HSL color (high saturation, medium lightness)
        bg_color = f"hsl({hue}, 65%, 45%)"

    letter = name[0].upper() if name else "?"
    letter_size = int(size * 0.45)
    radius = int(size * 0.15)

    return (
        f'<svg width="{size}" height="{size}" viewBox="0 0 {size} {size}" '
        f'xmlns="http://www.w3.org/2000/svg">'
        f'<rect width="{size}" height="{size}" rx="{radius}" fill="{bg_color}"/>'
        f'<text x="{size//2}" y="{size//2}" '
        f'text-anchor="middle" dominant-baseline="central" '
        f'fill="white" font-family="system-ui,sans-serif" '
        f'font-weight="700" font-size="{letter_size}">{letter}</text>'
        f'</svg>'
    )


# ══════════════════════════════════════════════════════════════════
#  RUNTIME REGISTRATION
# ══════════════════════════════════════════════════════════════════

def register(name: str, svg_content: str,
             default_color: str = "#666666",
             viewbox: str = "0 0 24 24",
             is_brand: bool = True) -> None:
    """
    Register a new icon at runtime — no file edit needed.

    For BRAND icons (fill-based): use "FILL" as color placeholder in svg_content.
    For GENERIC icons (stroke-based): set is_brand=False.

    Example:
        from utils.icons import register
        register(
            "flutter",
            '<path fill="FILL" d="M14.314 0L2.3 12 6 15.7 21.684.013h-7.357L14.314 0z"
             <path fill="FILL" d="M14.314 0l-8 8 4.357 4.357L22 0h-7.686z"/>',
            default_color="#54C5F8",
        )
    """
    if is_brand:
        BRAND_ICONS[name.lower()] = (viewbox, svg_content, default_color)
    else:
        ICON_PATHS[name.lower()] = svg_content

    # Also add to brand colors if default_color given
    if default_color and default_color.startswith("#"):
        BRAND_COLORS[name.lower()] = default_color

    print(f"  [Icons] Registered: '{name}'")


def register_topic(topic: str, icon_names_list: list[str]) -> None:
    """
    Register a topic → icon mapping so suggest_icons_for_topic() returns
    the right icons when that topic appears in content.

    Example:
        register_topic("flutter", ["flutter", "dart", "rocket", "layers", "sparkles"])
    """
    TOPIC_ICON_MAP[topic.lower()] = icon_names_list
    print(f"  [Icons] Topic registered: '{topic}' → {icon_names_list}")


# ══════════════════════════════════════════════════════════════════
#  TOPIC DETECTION — whole-word matching
# ══════════════════════════════════════════════════════════════════

# Topics where bare substring match is too risky (ambiguous short words)
_REQUIRES_WORD_BOUNDARY = {
    "go", "ml", "ai", "api", "npm", "r",
    "node_js", "nodejs", "java", "rust", "es",
}


def suggest_icons_for_topic(text: str) -> list[str]:
    """
    Detect brand/topic keywords in text and return relevant icon names.
    Uses whole-word matching for ambiguous short words to prevent false positives.
    E.g. "kubernetes node" → does NOT suggest nodejs icon.
    """
    text_lower = text.lower()
    matched: list[str] = []

    for topic, icons in TOPIC_ICON_MAP.items():
        topic_words = topic.replace("_", " ").replace("-", " ")
        needs_boundary = (topic in _REQUIRES_WORD_BOUNDARY or
                          len(topic.replace("_", "")) <= 3)

        if needs_boundary:
            pattern = r'\b' + re.escape(topic_words) + r'\b'
            if re.search(pattern, text_lower):
                matched.extend(icons)
        else:
            if topic_words in text_lower or topic in text_lower:
                matched.extend(icons)

    # Deduplicate preserving priority order
    seen: set[str] = set()
    result: list[str] = []
    for ic in matched:
        if ic not in seen:
            seen.add(ic)
            result.append(ic)
    return result


def get_brand_icon_names() -> list[str]:
    return sorted(BRAND_ICONS.keys())


def get_all_icon_names() -> list[str]:
    return sorted(
        list(ICON_PATHS.keys()) +
        list(BRAND_ICONS.keys()) +
        list(ICON_ALIASES.keys())
    )


# ══════════════════════════════════════════════════════════════════
#  RENDERER
# ══════════════════════════════════════════════════════════════════

def icon(name: str,
         size: int = 24,
         color: str = "currentColor",
         stroke_width: float = 2.0,
         extra_class: str = "") -> str:
    """
    Render an inline SVG icon. Always returns valid SVG — never fails.

    Priority: aliases → Tier 2 brand icons → Tier 1 generic icons → letter badge
    """
    size     = max(12, min(int(size), 200))
    resolved = ICON_ALIASES.get(name.lower(), name.lower())
    cls_attr = f' class="{extra_class}"' if extra_class else ""

    # Tier 2: Brand icon (fill-based)
    if resolved in BRAND_ICONS:
        viewbox, content, _ = BRAND_ICONS[resolved]
        content = content.replace("FILL", color)
        return (
            f'<svg{cls_attr} width="{size}" height="{size}" '
            f'viewBox="{viewbox}" xmlns="http://www.w3.org/2000/svg">'
            f'{content}</svg>'
        )

    # Tier 1: Generic stroke icon
    if resolved in ICON_PATHS:
        paths = ICON_PATHS[resolved]
        return (
            f'<svg{cls_attr} width="{size}" height="{size}" '
            f'viewBox="0 0 24 24" fill="none" '
            f'stroke="{color}" stroke-width="{stroke_width}" '
            f'stroke-linecap="round" stroke-linejoin="round" '
            f'xmlns="http://www.w3.org/2000/svg">'
            f'{paths}</svg>'
        )

    # Tier 3: Letter badge fallback (never breaks, always professional)
    return _letter_badge(resolved or name, size, color)


# ══════════════════════════════════════════════════════════════════
#  PLACEHOLDER SUBSTITUTION
# ══════════════════════════════════════════════════════════════════

_ICON_RE = re.compile(r'\[\[icon:([a-zA-Z0-9_\-\.]+):(\d+):([^\]]+)\]\]')


def substitute_icon_placeholders(html_text: str) -> str:
    """
    Replace all [[icon:NAME:SIZE:COLOR]] with inline SVG.
    Falls back to letter badge for unknown names — never leaves raw placeholders.
    """
    def replace(m: re.Match) -> str:
        return icon(m.group(1).strip(),
                    size=int(m.group(2).strip()),
                    color=m.group(3).strip())
    return _ICON_RE.sub(replace, html_text)